import { useState, useEffect } from "react";
import axios from "../axiosConfig";

const MentorPage = () => {
    const [mentors, setMentors] = useState([]);
    const [editingId, setEditingId] = useState(null);
    useEffect(() => {
    fetchMentors();
  }, []);

  const fetchMentors = async () => {
    try {
      const res = await axios.get("/api/mentors");
      setMentors(res.data);
    } catch (err) {
      console.error(err);
    }
  };
  const deleteMentor = async (id) => {
  try {
    await axios.delete(`/api/mentors/${id}`);
    fetchMentors(); // refresh list
  } catch (err) {
    console.error(err);
  }
};
  const [name, setName] = useState("");
  const [expertise, setExpertise] = useState("");
  const [availability, setAvailability] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
    if (editingId) {
      // UPDATE
      await axios.put(`/api/mentors/${editingId}`, {
        name,
        expertise,
        availability,
      });

      alert("Mentor updated!");
      setEditingId(null);
    } else {
      // CREATE
      await axios.post("/api/mentors", {
        name,
        expertise,
        availability,
      });

      alert("Mentor created!");
    }

    // clear form
    setName("");
    setExpertise("");
    setAvailability("");

    fetchMentors(); // refresh list
  } catch (err) {
    console.error(err);
    alert(err.response?.data?.message || "Error");
  }
  };

  return (
    <div>
      <h2>Add Mentor</h2>
      <h3>Mentor List</h3>

<ul>
  {mentors.map((mentor) => (
   <li key={mentor._id}>
  {mentor.name} - {mentor.expertise} - {mentor.availability}

  <button onClick={() => deleteMentor(mentor._id)}>
    Delete
  </button>
</li>
  ))}
</ul>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Name"
          onChange={(e) => setName(e.target.value)}
        />
        <input
          type="text"
          placeholder="Expertise"
          onChange={(e) => setExpertise(e.target.value)}
        />
        <input
          type="text"
          placeholder="Availability"
          onChange={(e) => setAvailability(e.target.value)}
        />
        <button type="submit">Add Mentor</button>
      </form>
    </div>
  );
};

export default MentorPage;
